<?php
namespace App\Domain\Combat\Data;
final class DamageMitigationResult{private $v;public function __construct(array $values){$this->v=$values;}public function incomingDamage(){return$this->v['incoming_damage'];}public function rawDefenseReductionBasisPoints(){return$this->v['raw_defense_reduction_basis_points'];}public function appliedDefenseReductionBasisPoints(){return$this->v['applied_defense_reduction_basis_points'];}public function damageAfterDefense(){return$this->v['damage_after_defense'];}public function rawAbsorbBasisPoints(){return$this->v['raw_absorb_basis_points'];}public function appliedAbsorbBasisPoints(){return$this->v['applied_absorb_basis_points'];}public function damageAfterAbsorb(){return$this->v['damage_after_absorb'];}public function minimumDamageByTotalCap(){return$this->v['minimum_damage_by_total_cap'];}public function finalDamage(){return$this->v['final_damage'];}public function toArray(){return array_merge([],$this->v);}}
